starterCode.css:
.page {
  display: grid;
  /* Define the rows */
  min-height: 100vh;
  margin: 0;
}

header { background: #3498db; padding: 20px; }
main { background: #ecf0f1; padding: 20px; color: #333; }
footer { background: #2c3e50; padding: 20px; }

.dashboard {
  display: grid;
  grid-template-columns: 200px repeat(2, 1fr);
  grid-template-rows: repeat(3, 100px);
  gap: 8px;
  max-width: 700px;
}

.cell {
  background: #e0e0e0; padding: 15px;
  border-radius: 4px; text-align: center;
  display: flex; align-items: center; justify-content: center;
}

.sidebar {
  /* Add spanning */
  background: #6c5ce7; color: white;
}

