solution.css:
.blog {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: repeat(2, 200px);
  grid-auto-rows: 150px;
  gap: 16px;
  max-width: 800px;
  margin: 0 auto;
}

.post {
  background: #f0f0f0; padding: 20px;
  border-radius: 8px; min-height: 100px;
}

.featured {
  grid-column: span 2;
  background: #ffd700;
}

.tall {
  min-height: 200px;
  background: #87ceeb;
}
